// The If node's input has resultJson as a STRING that needs parsing
const pollResponse = $input.first().json;

let imageUrl = null;

try {
  // Path 1: data.resultJson is a JSON string (KIE AI's actual shape)
  if (pollResponse?.data?.resultJson) {
    const parsed = typeof pollResponse.data.resultJson === 'string'
      ? JSON.parse(pollResponse.data.resultJson)
      : pollResponse.data.resultJson;
    imageUrl = parsed?.resultUrls?.[0] || null;
  }

  // Fallbacks just in case the shape changes
  if (!imageUrl) {
    imageUrl =
      pollResponse?.data?.resultUrls?.[0] ||
      pollResponse?.resultUrls?.[0] ||
      null;
  }
} catch (e) {
  throw new Error('Failed to parse resultJson: ' + e.message + ' | Raw: ' + JSON.stringify(pollResponse?.data?.resultJson).slice(0, 300));
}

if (!imageUrl) {
  throw new Error('No image URL found in poll response: ' + JSON.stringify(pollResponse).slice(0, 300));
}

// Grab metadata from THIS iteration of the loop, not the first item of the upstream node
const source = $('Loop Over Items').item.json;

return [{
  json: {
    imageUrl,
    variant_index: source.variant_index,
    template_index: source.template_index,
    template_url: source.template_url,
    aspect_ratio: source.aspect_ratio || '1:1',
    platform_label: source.platform_label || ''
  }
}];

const templates = $input.all();

// From Shuffle Templates, Webhook json is nested under .body
const webhookBody = $('Webhook').first().json.body || {};
const count = parseInt(webhookBody.static_ads_count) || 1;
const sampleSize = Math.min(count * 3, templates.length);

const arr = templates.slice();
for (var i = arr.length - 1; i > 0; i--) {
  var j = Math.floor(Math.random() * (i + 1));
  var tmp = arr[i]; arr[i] = arr[j]; arr[j] = tmp;
}

return arr.slice(0, sampleSize);

const templates = $input.all();

// From Pick Templates, Webhook json is nested under .body
const webhookBody = $('Webhook').first().json.body || {};
const count = parseInt(webhookBody.static_ads_count) || 1;

const referenceUrls = Array.isArray(webhookBody.reference_urls)
  ? webhookBody.reference_urls.filter(Boolean)
  : [];
const refCount = referenceUrls.length;

const refSlots = Math.min(refCount, count);
const airtableSlots = count - refSlots;

const arr = templates.slice();
for (var i = arr.length - 1; i > 0; i--) {
  var j = Math.floor(Math.random() * (i + 1));
  var tmp = arr[i]; arr[i] = arr[j]; arr[j] = tmp;
}
const airtablePicked = arr.slice(0, Math.min(airtableSlots, arr.length));

const result = [];

for (var r = 0; r < refSlots; r++) {
  result.push({
    json: {
      template_id: 'ref_' + r,
      template_url: referenceUrls[r],
      is_ref_slot: true,
      ref_index: r
    }
  });
}

airtablePicked.forEach(function(entry) {
  result.push({
    json: {
      template_id: String(entry.json.id),
      template_url: String(entry.json.template_image[0].url),
      is_ref_slot: false,
      ref_index: -1
    }
  });
});

return result;

const webhook = $('Webhook').first().json;
const body = webhook.body || {};  // nested under .body from this node's position
const brain = $('Search Brand Brain').first().json;

// === ASPECT RATIO + PLATFORM LABEL ===
const platformsRaw = String(body.platforms || '').toLowerCase();
let aspectRatio = '1:1';
if (platformsRaw.indexOf('9:16') > -1 || platformsRaw.indexOf('vertical') > -1) aspectRatio = '9:16';
else if (platformsRaw.indexOf('16:9') > -1 || platformsRaw.indexOf('youtube') > -1) aspectRatio = '16:9';
else if (platformsRaw.indexOf('1.91') > -1 || platformsRaw.indexOf('horizontal') > -1) aspectRatio = '16:9';
const platformLabel = String(body.platforms || '').split(',')[0].trim() || 'Meta / TikTok — Square (1:1)';

// === REFERENCES ===
const decode = $('Decode Reference').first().json;
const referenceUrls = (decode && Array.isArray(decode.reference_urls))
  ? decode.reference_urls.filter(Boolean)
  : [];
const refCount = referenceUrls.length;

// === LOGOS ===
const logoUrls = (Array.isArray(brain.logo_urls) ? brain.logo_urls : [])
  .map(function(l){ return (l && l.url) ? String(l.url) : null; })
  .filter(Boolean);
const primaryLogo = logoUrls[0] || null;

// === PRODUCTS (multi-select aware) ===
let productImageUrls = [];
if (Array.isArray(body.product_image_urls) && body.product_image_urls.length) {
  productImageUrls = body.product_image_urls.map(String).filter(Boolean);
} else if (body.product_image_url) {
  productImageUrls = [String(body.product_image_url)];
}

let productNames = [];
if (Array.isArray(body.product_names) && body.product_names.length) {
  productNames = body.product_names.map(String).filter(Boolean);
} else if (body.product_name) {
  productNames = String(body.product_name).split(',').map(function(s){ return s.trim(); }).filter(Boolean);
}

const isServiceBrand = productImageUrls.length === 0;
const isMultiProduct = productImageUrls.length > 1;
const productCount = productImageUrls.length;

// === KIE AI IMAGE BUDGET ===
// Max 16 images total per task.
// Slot 0: template or reference (always 1)
// Slots 1..P: products (mandatory — cap to fit budget)
// Slot last: logo (mandatory if exists)
const logoSlots = primaryLogo ? 1 : 0;
const maxProductSlots = 16 - 1 - logoSlots; // e.g. 16 - 1 - 1 = 14
productImageUrls = productImageUrls.slice(0, maxProductSlots);

// === TEMPLATE ITEMS from Pick Templates ===
// Pick Templates already assigned:
//   is_ref_slot: true  → template_url IS the user reference → reference is input_urls[0]
//   is_ref_slot: false → template_url is Airtable template  → Airtable image is input_urls[0]
const workItems = $input.all();

// === INPUT_URLS BUILDER ===
function buildInputUrls(item) {
  const urls = [item.template_url]; // always first — ref or airtable depending on slot type
  productImageUrls.forEach(function(u){ urls.push(u); });
  if (primaryLogo) urls.push(primaryLogo);
  return urls;
}

// === GUARDRAILS ===
const brandTypeGuardrail = isServiceBrand
  ? [
      'BRAND TYPE: SERVICE / B2B - No physical product.',
      '- DO NOT place brand name on random objects (cups, clothing, bags, packaging, signs).',
      '- Brand name appears ONLY in the designated logo zone, headline, and CTA.',
      '- Visual must represent the service outcome - clean workspace, documents, professional environment.'
    ].join('\n')
  : isMultiProduct
    ? [
        'BRAND TYPE: PRODUCT - Multiple products provided as visual hero.',
        '- ' + productCount + ' product images supplied: ' + productNames.join(', '),
        '- Feature ALL provided products. Either: (a) hero + supporting cast layout, or (b) product line-up / collection arrangement.',
        '- Use the EXACT product images provided - same shape, label, packaging, colors. Do NOT reimagine, replace, or merge into a single composite.',
        '- DO NOT swap in similar-looking products from training data.',
        '- DO NOT alter packaging text, label copy, ingredient lists, or product names. Render product packaging exactly as shown.',
        '- Brand name appears ONLY in the designated logo zone.'
      ].join('\n')
    : [
        'BRAND TYPE: PRODUCT - Feature the provided product image as the visual hero.',
        '- Use the EXACT product - same shape, label, packaging, colors, and PACKAGING FORM. The product form (pouch, bottle, jar, box, tube) comes ONLY from the provided product image. If the template shows a different form, DISCARD the template product and render the provided one. Never turn a pouch into a jar, or a jar into a bottle.',
        '- DO NOT alter packaging text, label copy, ingredient lists, or product names. Render product packaging exactly as shown.',
        '- DO NOT swap in similar-looking products from training data.',
        '- Brand name appears ONLY in the designated logo zone.'
      ].join('\n');

const brandIsolationRule = [
  'BRAND ISOLATION:',
  '- This ad is for "' + String(body.client_name || '') + '" ONLY.',
  '- DO NOT pull assets, products, packaging, color schemes, or visual cues from any sister brand or parent company.',
  '- The provided product images and logo are the ONLY visual sources of truth for this brand identity.'
].join('\n');

const logoRules = primaryLogo
  ? [
      'LOGO RULES:',
      '- Use the EXACT logo image provided as input. Do NOT stretch, recolor, restyle, or reinterpret.',
      '- Logo appears in ONE place only - the designated logo zone.',
      '- Maintain original logo aspect ratio. No distortion, no skewing.'
    ].join('\n')
  : 'LOGO RULES: No logo image provided. Render the brand name as clean typography in the logo zone only.';

const typographyRules = [
  'TYPOGRAPHY RULES:',
  '- Headline is the LARGEST text element, readable when scaled to a 200px thumbnail.',
  '- Visual hierarchy: HEADLINE > subhead > CTA > legal / disclaimer.',
  '- CTA button must be clearly emphasized with strong contrast.',
  '- Maximum 3 text elements unless the concept format (Notes/iMessage/review) requires more.',
  '- If the target persona is a senior demographic, scale body text 20% larger than default.',
  '- No em dashes in any visible text. Use commas or colons instead.',
  '- No gibberish text anywhere. Every visible word must be a real, intentional word.',
  '- Any legal disclaimer must be a single small footer line (8pt or smaller). Never larger.'
].join('\n');

const iconRules = [
  'ICON / UI RULES:',
  '- All icons must be clean, vector-style, single-line or simple-fill.',
  '- No blurry, fuzzy, sketched, or hand-drawn icon styles.',
  '- Checkmarks, arrows, and trust badges must be sharp and legible at full size.'
].join('\n');

const conceptPreservationRule = [
  'CONCEPT PRESERVATION (CRITICAL):',
  'The source image at input_urls[0] carries a specific CONCEPT FORMAT. Identify it and preserve it.',
  'Common valid concepts for DR static ads include:',
  '- iOS push notification (lock-screen mock with app icon, title, body, Skip/CTA buttons)',
  '- iOS Notes app screenshot (Notes header, title, bulleted checklist, orange CTA button)',
  '- iMessage toggle comparison (two iOS-style toggle rows showing pain vs solution)',
  '- Handwritten kid note / sticky note (paper texture, marker handwriting, casual)',
  '- Whiteboard line-drawing story ("This is [Name]. [Story]." stick figures)',
  '- Real-world billboard / out-of-home mockup (product on actual billboard with sky)',
  '- Customer review screenshot (5-star card with name, review text, optional photo)',
  '- Lifestyle hero with feature checklist (product photo + 3-4 checkmark bullets)',
  '- Bold typography on dark background (large stencil text, single price anchor)',
  '- Gift box reveal (product emerging from wrapped present, numbered steps)',
  '- Family testimonial with sticker callouts (photo + quote bubble + feature stickers)',
  '',
  'PICK ONE. Stay inside it. Do NOT mix concepts in a single ad.',
  '',
  'THIS IS NOT A BROCHURE. Hard rules:',
  '- ONE hook (the headline). ONE primary visual. ONE CTA.',
  '- Do NOT show 3 product variants side-by-side as equal heroes. Pick a hero.',
  '- Do NOT fill the canvas with 5+ feature icons in a row.',
  '- Do NOT include a large legal disclaimer block. If legal text is needed, single 8pt footer line ONLY.',
  '- The CTA must be the most prominent click target, not the 4th step in a flow.'
].join('\n');

const hallucinationGuardrail = [
  'ANTI-HALLUCINATION RULES:',
  '- No floating objects. Every object must rest on a surface or be held/supported logically.',
  '- No extra decorative artifacts not present in the source or supplied images.',
  '- No invented packaging variations, label changes, or fake product variants.',
  '- No fake awards, fake review counts, or fake press logos unless explicitly provided in the brand brain.',
  '- Realistic physics, shadows, and reflections only.',
  '- No broken anatomy if humans are present (correct count of fingers, eyes, limbs).'
].join('\n');

// === BRAND BRAIN FIELDS ===
const targetPersona = brain.target_personas ? String(brain.target_personas).slice(0, 800) : '';
const corePainPoints = brain.core_pain_points ? String(brain.core_pain_points).slice(0, 600) : '';
const productBenefits = brain.product_benefits ? String(brain.product_benefits).slice(0, 600) : '';
const brandGuidelines = brain.brand_guidelines ? String(brain.brand_guidelines).slice(0, 6000) : '';
const creativeBoundaries = brain.creative_boundaries ? String(brain.creative_boundaries).slice(0, 800) : '';

const angles = [
  'Lead with the core problem and pain point. Pain-first hook.',
  'Lead with the solution, outcome, and key benefit. Benefit-first hook.',
  'Lead with social proof, credibility, and trust. Trust-first hook.'
];

const result = [];

workItems.forEach(function(entry, tplIdx) {
  const item = entry.json;
  const isRefSlot = item.is_ref_slot === true;
  const inputUrls = buildInputUrls(item);

  // SOURCE MODE is per-item: ref slots use the uploaded reference as the creative source,
  // airtable slots use the template for layout only.
  const sourceModeBlock = isRefSlot
    ? [
        'SOURCE MODE: USER REFERENCE AD',
        'The image at input_urls[0] is a REFERENCE AD uploaded by the user as creative direction.',
        '- Use this reference for layout, style, tone, visual treatment, and concept format.',
        '- Match the reference precisely: composition, typography style, color treatment, photographic mood.',
        '- Replace all CONTENT (brand name, product, copy, logo) with THIS brand\'s assets.',
        '- The reference is the creative source of truth. Do NOT reinterpret, modernise, or improve it.',
        '- This reference was chosen because it represents a style direction the client wants to explore.'
      ].join('\n')
    : [
        'SOURCE MODE: AD TEMPLATE',
        'The image at input_urls[0] is a layout TEMPLATE from our creative library.',
        '- Keep the exact layout, composition, and design structure of the template.',
        '- Replace all visual content, colors, copy, and imagery to match THIS brand. Any product shown in the template belongs to a DIFFERENT brand and must be replaced entirely by the provided product image. Keep the template LAYOUT, never its product shape or packaging.',
        '- The template is for layout reference only — do NOT keep its original copy or images.'
      ].join('\n');

  angles.forEach(function(angle, vIdx) {
    const lines = [
      'Transform this source image into a static, performance-ready DR ad creative.',
      '',
      'BRAND: ' + String(body.client_name || ''),
      productNames.length ? 'PRODUCT(S): ' + productNames.join(', ') : '',
      'BRAND TONE: ' + String(brain.brand_tone || ''),
      'KEY OFFER: ' + String(brain.key_offer || ''),
      productBenefits ? 'KEY BENEFITS: ' + productBenefits : '',
      targetPersona ? 'TARGET PERSONA: ' + targetPersona : '',
      corePainPoints ? 'CORE PAIN POINTS: ' + corePainPoints : '',
      'BRIEF: ' + String(body.brief || ''),
      '',
      sourceModeBlock,
      '',
      brandTypeGuardrail,
      '',
      'COPY ANGLE: ' + angle,
      '',
      brandIsolationRule,
      '',
      logoRules,
      '',
      typographyRules,
      '',
      iconRules,
      '',
      conceptPreservationRule,
      '',
      hallucinationGuardrail,
      brandGuidelines ? '\nBRAND GUIDELINES:\n' + brandGuidelines : '',
      creativeBoundaries ? '\nCREATIVE BOUNDARIES (do NOT do these):\n' + creativeBoundaries : '',
      '',
      'FINAL CHECK before output:',
      '1. Is the brand name in ONLY one place (the logo zone)?',
      '2. Is each product image the EXACT one provided (no swaps, no hallucinated packaging)?',
      '3. Is the headline the largest text element?',
      '4. Are all icons sharp and clean?',
      '5. Are there ANY floating objects or hallucinated elements? Remove them.',
      '6. Did you stay inside ONE concept format? No mixing.',
      '7. Is this ONE hook, ONE visual, ONE CTA? Not a brochure?',
      '8. Is any legal text limited to a single 8pt footer line?',
      isRefSlot ? '9. Does the output match the reference\'s style and feel precisely?' : null
    ].filter(Boolean);

    result.push({
      json: {
        template_url: item.template_url,
        template_index: tplIdx + 1,
        input_urls: inputUrls,
        prompt: lines.join('\n'),
        variant_index: vIdx + 1,
        is_reference_based: isRefSlot,
        aspect_ratio: aspectRatio,
        platform_label: platformLabel
      }
    });
  });
});

return result;

